 750 static void computeKnownBitsFromCond(const Value *V, Value *Cond,
 751                                      KnownBits &Known, unsigned Depth,
 752                                      const SimplifyQuery &SQ, bool Invert) {
 753   Value *A, *B;
 754   if (Depth < MaxAnalysisRecursionDepth &&
 755       match(Cond, m_LogicalOp(m_Value(A), m_Value(B)))) {
